const { execSync } = require('child_process');
const fs = require('fs');

try {
  // Execute systemctl command to get all services
  const output = execSync('systemctl list-units --type=service --all --no-pager', { 
    encoding: 'utf-8',
    maxBuffer: 10 * 1024 * 1024 
  });

  // Write to file
  fs.writeFileSync('/tmp/mcp-workspace/services_status.txt', output);

  console.log('Successfully saved services status to /tmp/mcp-workspace/services_status.txt');
} catch (error) {
  console.error(`Error: ${error.message}`);
}


